import{_ as e,o as a,c as t,d as i}from"./app.22d6dd61.js";const m=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[{"level":2,"title":"Preamble","slug":"preamble"},{"level":2,"title":"Navigation","slug":"navigation"},{"level":2,"title":"Tutorial Updates","slug":"tutorial-updates"},{"level":2,"title":"Learn More","slug":"learn-more"}],"relativePath":"index.md","lastUpdated":1659428266000}'),o={name:"index.md"},r=i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-hidden="true">#</a></h1><p>Welcome to the Hyperledger Iroha 2 tutorial. This document is designed to help you get started with Iroha 2, regardless of your knowledge of Hyperledger technology, coding experience or familiarity with blockchains.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you have previously worked with Iroha, start with our comparison of <a href="./guide/iroha-2.html">Iroha 1 and Iroha 2</a>. That will help you understand the differences between the two versions and upgrade to the newer one.</p></div><h2 id="preamble" tabindex="-1">Preamble <a class="header-anchor" href="#preamble" aria-hidden="true">#</a></h2><p>This tutorial is suitable for both experienced developers, prospective users, and people casually curious about blockchain technology. The level of detail is sufficient so that you wouldn&#39;t need any supplementary guide. However, should you want to learn more, we have more detailed documentation in the works.</p><p>In this guide, we shall</p><ul><li>walk you through starting an Iroha network, either with docker (recommended) or using one of the provided scripts;</li><li>introduce you to the client libraries;</li><li>take a small detour into the basic concepts of Iroha special instructions, and how they interact with the world state.</li></ul><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-hidden="true">#</a></h2><p>We invite you to follow the tutorial in this order:</p><ol start="0"><li>If you are already familiar with Hyperledger Iroha, read about <a href="./guide/iroha-2.html">the differences</a> between two versions of Iroha.</li><li><a href="./guide/build-and-install.html">Build and install Iroha 2</a>, then follow one of the language-specific guides to learn how to set up and configure Iroha 2, register a domain and an account, register and mind assets, and visualize outputs: <ul><li><a href="./guide/bash.html">Bash</a></li><li><a href="./guide/python.html">Python</a></li><li><a href="./guide/rust.html">Rust</a></li><li><a href="./guide/kotlin-java.html">Kotlin/Java</a></li><li><a href="./guide/javascript.html">Javascript (TypeScript)</a></li></ul></li><li>Dive into more advanced topics to deepen your understanding of Iroha 2: <ul><li>Check the <a href="./guide/advanced/intro.html">features that make Iroha truly special</a>.</li><li>Learn in greater detail about Iroha 2 <a href="./guide/configure/intro.html">configuration and management</a>.</li></ul></li><li>Use Iroha 2 in a more advanced mode: <ul><li><a href="./guide/advanced/running-iroha-on-bare-metal.html">Run Iroha on bare metal</a>.</li></ul></li></ol><h2 id="tutorial-updates" tabindex="-1">Tutorial Updates <a class="header-anchor" href="#tutorial-updates" aria-hidden="true">#</a></h2><p>The current iteration of the Iroha 2 tutorial is a constant work in progress. We are updating the tutorial with each release to reflect the state of Iroha and the newly added features. While we do our best to keep this tutorial up to date, it can go out of sync by a few days or maybe a week.</p><p>In the future this tutorial will have sections dedicated to:</p><ul><li>permissions</li><li>multi-signature accounts and transactions</li><li>custom permission validators</li><li>permission groups</li></ul><p>We will also cover peer management in greater detail: adding and removing peers, maintaining a healthy network, and troubleshooting the issues that you might have in your real-world application.</p><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-hidden="true">#</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>For more information on Iroha 2, please take a look at the <a href="https://github.com/hyperledger/iroha/blob/iroha2/docs/source/iroha_2_whitepaper.md" target="_blank" rel="noopener noreferrer">Iroha 2 Whitepaper</a>, as well as the Hyperledger Iroha section within the <a href="https://wiki.hyperledger.org/display/iroha" target="_blank" rel="noopener noreferrer">Hyperledger Foundation Wiki</a>.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you want to contribute to Hyperledger Iroha, please look at our <a href="https://github.com/hyperledger/iroha/blob/iroha2-dev/CONTRIBUTING.md" target="_blank" rel="noopener noreferrer">Contributing Guide</a>.</p></div>',18),l=[r];function n(h,s,d,u,c,p){return a(),t("div",null,l)}var f=e(o,[["render",n]]);export{m as __pageData,f as default};
